package com.alipay.antchain.l2.relayer.commoms;

import java.math.BigInteger;
import java.util.List;
import java.util.stream.Collectors;

import cn.hutool.core.util.HexUtil;
import cn.hutool.core.util.StrUtil;
import com.alibaba.fastjson.JSON;
import com.alipay.antchain.l2.relayer.commons.l2basic.BatchHeader;
import com.alipay.antchain.l2.relayer.commons.l2basic.BatchVersionEnum;
import com.alipay.antchain.l2.relayer.commons.l2basic.BlockContext;
import com.alipay.antchain.l2.relayer.commons.l2basic.Chunk;
import org.junit.Test;

import static org.junit.Assert.*;

public class BatchStructsTest {

    private static final String RAW_BATCH_HEADER = "000000000000000064d6c4f2bbcb2b643ffe818fa4c4cd168b2e82efc6980b44f47137ec5c0c8e915abea6b264593ec8f7f9dee8377db795143903400f6dadc70074330861a38ea769ca25b236584c68901b25d6b8af6ebe6fa8ac68f2c40af09cebc488d674ad73a0";

    private static final List<BlockContext> BLOCK_CONTEXTS = JSON.parseArray("""
                    [
                    	"0000000100000000000000010000019482fd29860000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000020000019482fd354e0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000030000019482fd410d0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000040000019482fd4cd60000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000050000019482fd589d0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000060000019482fd64660000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000070000019482fd702e0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000080000019482fd7bf60000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000090000019482fd87be0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000a0000019482fd93860000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000b0000019482fd9f4e0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000c0000019482fdab170000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000d0000019482fdb6df0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000e0000019482fdc2a80000000000000000000000003b9aca0000000000",
                    	"00000001000000000000000f0000019482fdce700000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000100000019482fdda380000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000110000019482fde6000000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000120000019482fdf1c90000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000130000019482fdfd910000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000140000019482fe095a0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000150000019482fe15220000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000160000019482fe20eb0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000170000019482fe2cb20000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000180000019482fe387b0000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000190000019482fe44440000000000000000000000003b9aca0000000000",
                    	"00000001000000000000001a0000019482fe4d920000000000000000000000003b9aca0000010000",
                    	"00000001000000000000001b0000019482fe4e000000000000000000000000003b9aca0000000000",
                    	"00000001000000000000001c0000019482fe4e6e0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000001d0000019482fe4edc0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000001e0000019482fe4f4b0000000000000000000000003b9aca0000000000",
                    	"00000001000000000000001f0000019482fe4fb90000000000000000000000003b9aca0000000000",
                    	"0000000100000000000000200000019482fe50270000000000000000000000003b9aca0000000000"
                    ]""")
            .stream().map(x -> (String) x).map(HexUtil::decodeHex).map(BlockContext::deserializeFrom).collect(Collectors.toList());

    private static final String RAW_CHUNK = "";

    private static final String RAW_BLK_CONTEXT_0 = "0000000100000000000000010000019482fd29860000000000000000000000003b9aca0000000000";

    @Test
    public void testBatchHeader() {
        BatchHeader header = BatchHeader.deserializeFrom(HexUtil.decodeHex(RAW_BATCH_HEADER));
        assertEquals(BatchVersionEnum.BATCH_V0, header.getVersion());
        assertEquals(BigInteger.valueOf(100), header.getBatchIndex());
        assertArrayEquals(HexUtil.decodeHex("d6c4f2bbcb2b643ffe818fa4c4cd168b2e82efc6980b44f47137ec5c0c8e915a"), header.getL1MsgRollingHash());
        assertArrayEquals(HexUtil.decodeHex("bea6b264593ec8f7f9dee8377db795143903400f6dadc70074330861a38ea769"), header.getDataHash());
        assertArrayEquals(HexUtil.decodeHex("ca25b236584c68901b25d6b8af6ebe6fa8ac68f2c40af09cebc488d674ad73a0"), header.getParentBatchHash());

        assertEquals(RAW_BATCH_HEADER, HexUtil.encodeHexStr(header.serialize()));

        assertTrue(BatchVersionEnum.BATCH_V1.isBatchDataCompressionSupport());
    }

    @Test
    public void testBlockContext() {
        BlockContext context = BlockContext.deserializeFrom(HexUtil.decodeHex(RAW_BLK_CONTEXT_0));
        assertEquals(1, context.getSpecVersion());
        assertEquals(BLOCK_CONTEXTS.get(0).getBlockNumber(), context.getBlockNumber());
        assertEquals(BLOCK_CONTEXTS.get(0).getTimestamp(), context.getTimestamp());
        assertEquals(BLOCK_CONTEXTS.get(0).getBaseFee(), context.getBaseFee());
        assertEquals(BLOCK_CONTEXTS.get(0).getGasLimit(), context.getGasLimit());
        assertEquals(BLOCK_CONTEXTS.get(0).getNumL1Messages(), context.getNumL1Messages());
        assertEquals(BLOCK_CONTEXTS.get(0).getNumTransactions(), context.getNumTransactions());

        assertEquals(RAW_BLK_CONTEXT_0, HexUtil.encodeHexStr(context.serialize()));
    }

    @Test
    public void testChunk() {
        var chunk = Chunk.deserializeFrom(HexUtil.decodeHex(RAW_CHUNK));
        assertEquals(1, chunk.getL2TransactionHashes().size());
        assertEquals(1, chunk.getL2TransactionList().size());
        assertEquals(32, chunk.getBlocks().size());
        assertEquals(32, chunk.getNumBlocksVal());
        for (int i = 0; i < chunk.getBlocks().size(); ++i) {
            BlockContext blockContext = BLOCK_CONTEXTS.get(i);
            BlockContext deserializedBlockContext = chunk.getBlocks().get(i);
            assertEquals(blockContext.getBlockNumber(), deserializedBlockContext.getBlockNumber());
            assertEquals(blockContext.getTimestamp(), deserializedBlockContext.getTimestamp());
            assertEquals(blockContext.getBaseFee(), deserializedBlockContext.getBaseFee());
            assertEquals(blockContext.getGasLimit(), deserializedBlockContext.getGasLimit());
            assertEquals(blockContext.getNumL1Messages(), deserializedBlockContext.getNumL1Messages());
            assertEquals(blockContext.getNumTransactions(), deserializedBlockContext.getNumTransactions());
        }

        assertTrue(StrUtil.equalsIgnoreCase(RAW_CHUNK, HexUtil.encodeHexStr(chunk.serialize())));
    }
}
